import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Button, icon } from 'decantr/components';

code.example:
function BrandCta() {
  const { div, h2, p, span } = tags;

  return div({ class: css('_flex _col _aic _tc _gap8 _py24 _px6 _relative d-mesh') },
    span({ class: css('aura-orb _w[300px] _h[300px] _top[10%] _right[-5%] _bg[rgba(254,68,116,0.12)]') }),
    h2({ class: css('d-heading-display d-gradient-text') }, 'Start building today'),
    p({ class: css('_body _fgmuted _mw[540px] _textlg') }, 'Join thousands of developers shipping faster with the AI-first web framework.'),
    div({ class: css('_flex _gap3') },
      Button({ variant: 'primary', size: 'lg', class: css('aura-glow') }, 'Get Started Free'),
      Button({ variant: 'outline', size: 'lg' }, icon('arrow-right'), 'Read the Docs')
    )
  );
}

